constexpr int32_t BUFFER_NUM = 2;

class KernelCa6k00518Custom {
public:
    __aicore__ inline KernelCa6k00518Custom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y,
                                uint32_t totalLength, uint32_t dimSize,
                                uint32_t tileLength)
    {
        totalLen_ = totalLength;
        dimSize_ = dimSize;
        tileLen_ = dimSize;

        xGm_.SetGlobalBuffer((__gm__ float*)x, totalLen_);
        yGm_.SetGlobalBuffer((__gm__ float*)y, totalLen_);

        pipe_.InitBuffer(inQueueX_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(tmpQueue_, 4, tileLen_ * sizeof(float));
    }

    __aicore__ inline void Process()
    {
        if (totalLen_ == 0 || dimSize_ == 0) return;

        const uint32_t blockNum = static_cast<uint32_t>(AscendC::GetBlockNum());
        const uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());

        uint32_t numVectors = totalLen_ / dimSize_;

        for (uint32_t v = blockIdx; v < numVectors; v += blockNum) {
            uint32_t base = v * dimSize_;

            AscendC::LocalTensor<float> xVec = inQueueX_.AllocTensor<float>();
            AscendC::DataCopy(xVec, xGm_[base], dimSize_);

            AscendC::LocalTensor<float> negX = tmpQueue_.AllocTensor<float>();
            AscendC::Neg(negX, xVec, dimSize_);

            AscendC::LocalTensor<float> shiftVal = tmpQueue_.AllocTensor<float>();
            AscendC::ReduceMax(shiftVal, negX, dimSize_);
            float shift = shiftVal.GetValue(0);

            AscendC::Adds(negX, negX, shift, dimSize_);

            AscendC::Exp(negX, negX, dimSize_);

            AscendC::LocalTensor<float> sumVal = tmpQueue_.AllocTensor<float>();
            AscendC::ReduceSum(sumVal, negX, dimSize_);
            float sumInv = 1.0f / sumVal.GetValue(0);

            AscendC::Muls(negX, negX, sumInv, dimSize_);

            AscendC::DataCopy(yGm_[base], negX, dimSize_);

            tmpQueue_.FreeTensor(shiftVal);
            tmpQueue_.FreeTensor(sumVal);
            tmpQueue_.FreeTensor(negX);
            inQueueX_.FreeTensor(xVec);
        }
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueueX_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 4> tmpQueue_;

    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> yGm_;

    uint32_t totalLen_ {0};
    uint32_t dimSize_ {0};
    uint32_t tileLen_ {0};
};

